import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos } from '../services/productoService';
import { registrarVenta } from '../services/ventaService';

const Ventas = () => {
    const navigate = useNavigate();
    const [productos, setProductos] = useState([]);
    const [carrito, setCarrito] = useState({
        productoId: '',
        codigo: '',
        nombre: '',
        precio: 0,
        cantidad: 1,
        stockDisponible: 0
    });
    const [pago, setPago] = useState({
        efectivo: 0,
        cambio: 0
    });
    const [ventaRealizada, setVentaRealizada] = useState(null);

    useEffect(() => {
        if (!localStorage.getItem('usuarioLogueado')) {
            navigate("/");
        } else {
            const fetchProds = async () => {
                const data = await obtenerProductos();
                setProductos(data);
            };
            fetchProds();
        }
    }, [navigate]);

    // Calcular cambio automáticamente
    useEffect(() => {
        const totalVenta = carrito.precio * carrito.cantidad;
        setPago(prev => ({ ...prev, cambio: prev.efectivo - totalVenta }));
    }, [pago.efectivo, carrito.precio, carrito.cantidad]);

    const seleccionarProducto = (e) => {
        const prodId = e.target.value;
        const prod = productos.find(p => p.id.toString() === prodId);
        
        if (prod) {
            setCarrito({
                productoId: prod.id,
                codigo: prod.codigo,
                nombre: prod.nombre,
                precio: prod.precioVenta,
                cantidad: 1,
                stockDisponible: prod.stock
            });
        }
    };

    const handleVenta = async (e) => {
        e.preventDefault();
        const matricula = localStorage.getItem('usuarioLogueado');
        const totalVenta = carrito.precio * carrito.cantidad;

        if (pago.efectivo < totalVenta) {
            alert("❌ El efectivo es insuficiente.");
            return;
        }

        const datos = {
            codigoProducto: carrito.codigo,
            nombreProducto: carrito.nombre,
            cantidad: carrito.cantidad,
            precioVenta: carrito.precio,
            vendedorMatricula: matricula
        };

        const resultado = await registrarVenta(datos);
        if (resultado) {
            setVentaRealizada({ ...resultado, efectivo: pago.efectivo, cambio: pago.cambio });
            alert("✅ Venta realizada con éxito");
            setTimeout(() => {
                window.print();
                // Limpiar todo después de la venta
                setCarrito({ productoId: '', codigo: '', nombre: '', precio: 0, cantidad: 1, stockDisponible: 0 });
                setPago({ efectivo: 0, cambio: 0 });
            }, 500);
        }
    };

    return (
        <div style={{ padding: '30px', fontFamily: 'Arial', maxWidth: '800px', margin: '0 auto' }}>
            <div className="no-print">
                <h2 style={{ color: '#007bff', textAlign: 'center' }}>🛒 Terminal de Venta - Isla Tecnológica</h2>
                
                <div style={{ background: '#f8f9fa', padding: '25px', borderRadius: '15px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
                    <form onSubmit={handleVenta}>
                        <div style={{ marginBottom: '15px' }}>
                            <label style={{ fontWeight: 'bold' }}>Producto:</label>
                            <select 
                                onChange={seleccionarProducto} 
                                style={{ width: '100%', padding: '12px', marginTop: '5px', borderRadius: '8px' }}
                                required
                            >
                                <option value="">-- Seleccionar --</option>
                                {productos.map(p => (
                                    <option key={p.id} value={p.id}>
                                        {p.nombre} ({p.codigo})
                                    </option>
                                ))}
                            </select>
                        </div>

                        {carrito.productoId && (
                            <>
                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px', marginBottom: '20px' }}>
                                    <div>
                                        <label style={{ fontWeight: 'bold' }}>Cantidad:</label>
                                        <input type="number" min="1" max={carrito.stockDisponible} value={carrito.cantidad} onChange={(e) => setCarrito({...carrito, cantidad: parseInt(e.target.value)})} style={{ width: '100%', padding: '10px', marginTop: '5px', borderRadius: '8px' }} />
                                    </div>
                                    <div>
                                        <label style={{ fontWeight: 'bold' }}>Precio Unit. ($):</label>
                                        <input type="number" step="0.01" value={carrito.precio} onChange={(e) => setCarrito({...carrito, precio: parseFloat(e.target.value)})} style={{ width: '100%', padding: '10px', marginTop: '5px', borderRadius: '8px', border: '2px solid #007bff' }} />
                                    </div>
                                    <div>
                                        <label style={{ fontWeight: 'bold' }}>Subtotal:</label>
                                        <div style={{ fontSize: '22px', fontWeight: 'bold', color: '#28a745', marginTop: '10px' }}>
                                            ${(carrito.precio * carrito.cantidad).toFixed(2)}
                                        </div>
                                    </div>
                                </div>

                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginBottom: '20px', borderTop: '1px solid #ccc', paddingTop: '20px' }}>
                                    <div>
                                        <label style={{ fontWeight: 'bold' }}>Paga con (Efectivo):</label>
                                        <input type="number" step="0.01" value={pago.efectivo} onChange={(e) => setPago({...pago, efectivo: parseFloat(e.target.value)})} style={{ width: '100%', padding: '10px', marginTop: '5px', borderRadius: '8px', fontSize: '18px' }} />
                                    </div>
                                    <div>
                                        <label style={{ fontWeight: 'bold' }}>Cambio:</label>
                                        <div style={{ fontSize: '24px', fontWeight: 'bold', color: pago.cambio < 0 ? 'red' : 'blue', marginTop: '5px' }}>
                                            ${pago.cambio.toFixed(2)}
                                        </div>
                                    </div>
                                </div>
                            </>
                        )}

                        <button type="submit" disabled={!carrito.productoId || pago.cambio < 0} style={{ width: '100%', padding: '15px', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>
                            CONFIRMAR VENTA E IMPRIMIR
                        </button>
                    </form>
                </div>
            </div>

            {/* TICKET ESTILO PROFESIONAL */}
            <div className="print-only" style={{ width: '80mm', padding: '5mm', fontFamily: 'monospace', fontSize: '12px' }}>
                <div style={{ textAlign: 'center' }}>
                    <h2 style={{ margin: '0' }}>ISLA TECNOLÓGICA</h2>
                    <p style={{ margin: '0' }}>Mérida, Yucatán</p>
                    <p style={{ margin: '0' }}>CP 97000</p>
                    <p>--------------------------------</p>
                </div>
                
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <span>Venta: {ventaRealizada?.id}</span>
                    <span>{new Date().toLocaleDateString()}</span>
                </div>
                <div style={{ textAlign: 'right' }}>{new Date().toLocaleTimeString()}</div>
                <p>Cliente: Público en General</p>
                <p>--------------------------------</p>

                <div style={{ marginBottom: '10px' }}>
                    <div>{ventaRealizada?.cantidad} x {ventaRealizada?.nombreProducto}</div>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <span>${ventaRealizada?.precioVenta?.toFixed(2)}</span>
                        <span>${ventaRealizada?.total?.toFixed(2)}</span>
                    </div>
                </div>

                <p>--------------------------------</p>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold' }}>
                    <span>TOTAL:</span>
                    <span>MXN: ${ventaRealizada?.total?.toFixed(2)}</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <span>Efectivo:</span>
                    <span>${ventaRealizada?.efectivo?.toFixed(2)}</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <span>Cambio:</span>
                    <span>${ventaRealizada?.cambio?.toFixed(2)}</span>
                </div>
                
                <p style={{ textAlign: 'center', marginTop: '10px' }}>Precios incluyen impuestos*</p>
                
                <div style={{ textAlign: 'center', marginTop: '15px' }}>
                    <p style={{ margin: '0' }}>Atendido por: {ventaRealizada?.vendedorMatricula}</p>
                    <p style={{ fontSize: '10px' }}>ID: {Math.random().toString(36).substr(2, 9).toUpperCase()}</p>
                    <p style={{ marginTop: '10px' }}>¡Gracias por su preferencia!</p>
                </div>
            </div>
        </div>
    );
};

export default Ventas;
